if !createArgs.Force {
	// Search for existing open or in_progress issues with same title
	// We use TitleSearch for exact match (it filters by exact title internally)
	statusOpen := types.StatusOpen
	filter := types.IssueFilter{
		Status:      &statusOpen,
		TitleSearch: createArgs.Title,
	}
	issues, err := store.SearchIssues(ctx, "", filter)
	if err != nil {
		return Response{
			Success: false,
			Error:   fmt.Sprintf("failed to check for duplicate titles: %v", err),
		}
	}
	// Also check in_progress status
	statusInProgress := types.StatusInProgress
	filterInProgress := types.IssueFilter{
		Status:      &statusInProgress,
		TitleSearch: createArgs.Title,
	}
	inProgressIssues, err := store.SearchIssues(ctx, "", filterInProgress)
	if err != nil {
		return Response{
			Success: false,
			Error:   fmt.Sprintf("failed to check for duplicate titles: %v", err),
		}
	}
	issues = append(issues, inProgressIssues...)

	// Filter to exact title match (TitleSearch may do substring matching)
	var exactMatches []*types.Issue
	for _, issue := range issues {
		if issue.Title == createArgs.Title {
			exactMatches = append(exactMatches, issue)
		}
	}

	if len(exactMatches) > 0 {
		// Found existing issue with same title - return it instead of creating duplicate
		existingIssue := exactMatches[0]
		data, err := json.Marshal(existingIssue)
		if err != nil {
			return Response{
